#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
int fa[100010][31],d[100010],lg[100010];
int son[100010][31];
void dfs(int x,int f=0)
{
    if(f==0)
    {
        f=x;
    }
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=30;i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        dfs(i,x);
    }
    if(!mp[x].empty())
    {
        son[x][0]=mp[x][0];
    }
    else
    {
        son[x][0]=x;
    }
    for(int i=1;i<=30;i++)
    {
        son[x][i]=son[son[x][i-1]][i-1];
    }
}
int main()
{
    int n,q;
    scanf("%d%d",&n,&q);
    for(int i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(int i=2;i<=n;i++)
    {
        int p;
        scanf("%d",&p);
        mp[p].push_back(i);
    }
    for(int i=1;i<=n;i++)
    {
        sort(mp[i].begin(),mp[i].end());
    }
    dfs(1);
    for(int i=1;i<=q;i++)
    {
        int s,k;
        scanf("%d%d",&s,&k);
        for(int i=1;i<=k;i++)
        {
            int x;
            scanf("%d",&x);
            if(x>0)
            {
                for(int j=0;j<=30;j++)
                {
                    if(x&(1<<j))
                    {
                        s=fa[s][j];
                    }
                }
            }
            else
            {
                x=-x;
                for(int j=0;j<=30;j++)
                {
                    if(x&(1<<j))
                    {
                        s=son[s][j];
                    }
                }
            }
        }
        printf("%d\n",s);
    }
    return 0;
}
